for _ in range(3):
    batch_error_count = 2
    batch_success_count = 0
    if batch_success_count > 0:
        consecutive_action_errors = 0
    elif batch_error_count > 0:
        consecutive_action_errors += 1
FINAL(consecutive_action_errors)
"#,
