    pub struct InMemoryStore {
        threads: RwLock<Vec<Thread>>,
        steps: RwLock<Vec<Step>>,
        events: RwLock<Vec<ThreadEvent>>,
        projects: RwLock<Vec<Project>>,
        conversations: RwLock<Vec<ConversationSurface>>,
