    #[test]
    fn trace_serializes_approval_request_payload() {
        let mut thread = make_thread();
        thread.add_message(ThreadMessage::system("sys"));
        thread.add_message(ThreadMessage::assistant("installing notion"));
        thread.events.push(ThreadEvent::new(
            thread.id,
            EventKind::ApprovalRequested {
                action_name: "tool_install".into(),
                call_id: "call_install_1".into(),
                parameters: Some(serde_json::json!({"name": "notion", "kind": "mcp_server"})),
                description: Some("Install an extension".into()),
                allow_always: Some(true),
                gate_name: Some("approval".into()),
                params_summary: Some("notion".into()),
            },
        ));

        let trace = build_trace(&thread);
        // `Thread::add_message` records a `MessageAdded` event for each
        // message, so the `ApprovalRequested` event is no longer at index 0
        // — it's mixed in with the message events. Find it by kind.
        let approval = trace
            .events
            .iter()
            .find(|e| matches!(&e.kind, EventKind::ApprovalRequested { .. }))
            .expect("trace should contain an ApprovalRequested event");
        match &approval.kind {
            EventKind::ApprovalRequested {
                action_name,
                call_id,
                parameters,
                description,
                allow_always,
                gate_name,
                params_summary,
            } => {
                assert_eq!(action_name, "tool_install");
                assert_eq!(call_id, "call_install_1");
                assert_eq!(
                    parameters.as_ref().and_then(|p| p.get("name")),
                    Some(&serde_json::json!("notion"))
                );
                assert_eq!(description.as_deref(), Some("Install an extension"));
                assert_eq!(*allow_always, Some(true));
                assert_eq!(gate_name.as_deref(), Some("approval"));
                assert_eq!(params_summary.as_deref(), Some("notion"));
            }
            other => panic!("unexpected event kind: {other:?}"),
        }

        let json = serde_json::to_string(&trace).expect("trace serializes");
        assert!(json.contains("\"ApprovalRequested\""));
        assert!(json.contains("\"action_name\":\"tool_install\""));
        assert!(json.contains("\"call_id\":\"call_install_1\""));
        // Parameter map key order isn't stable across serde_json versions; check
        // both required keys are present rather than the exact serialized form.
        assert!(json.contains("\"name\":\"notion\""));
        assert!(json.contains("\"kind\":\"mcp_server\""));
        assert!(json.contains("\"description\":\"Install an extension\""));
        assert!(json.contains("\"allow_always\":true"));
        assert!(json.contains("\"gate_name\":\"approval\""));
        assert!(json.contains("\"params_summary\":\"notion\""));
    }
}

//! IronClaw Engine — unified thread-capability-CodeAct execution model.
//!
//! This crate provides the core execution engine for IronClaw, unifying
//! ~10 separate abstractions (Session, Job, Routine, Channel, Tool, Skill,
//! Hook, Observer, Extension, LoopDelegate) around 5 primitives:
//!
//! - **Thread** — unit of work (replaces Session + Job + Routine + Sub-agent)
//! - **Step** — unit of execution (replaces agentic loop iteration + tool calls)
//! - **Capability** — unit of effect (replaces Tool + Skill + Hook + Extension)
//! - **MemoryDoc** — unit of durable knowledge (replaces workspace memory blobs)
//! - **Project** — unit of context (replaces flat workspace namespace)
//!
//! The engine defines traits for external dependencies ([`LlmBackend`],
//! [`Store`], [`EffectExecutor`]) that the host crate implements via bridge
//! adapters over existing infrastructure.

// Security: `__regex_match__` (in `executor/orchestrator.rs`) accepts
// arbitrary patterns from the Python orchestrator and runs them on
// user-supplied text. The default `regex` crate is linear-time. The
// `fancy-regex` crate supports backreferences and is NOT linear-time, which
// would turn that handler into a ReDoS vector. Cargo.toml depends on
// `regex = "1"` with default features only — do NOT add `fancy-regex` to
// this crate's dependency tree without first redesigning `__regex_match__`
// to enforce a wall-clock matching budget.

