            let mut threads = self.threads.write().await;
            threads.retain(|t| t.id != thread.id);
            threads.push(thread.clone());
            Ok(())
        }
        async fn load_thread(&self, id: ThreadId) -> Result<Option<Thread>, EngineError> {
            Ok(self
