//! Event sourcing types.
//!
//! Every significant action within a thread is recorded as an event.
//! This enables replay, debugging, reflection, and trace-based testing.

use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use uuid::Uuid;

use crate::types::capability::LeaseId;

/// Generate a short human-readable summary of tool parameters for display.
///
/// For `http`: shows the URL. For `web_search`: shows the query.
/// For other tools: shows the first string argument, truncated.
/// Returns `None` for empty or unrecognizable params.
pub fn summarize_params(action_name: &str, params: &serde_json::Value) -> Option<String> {
    let summary = match action_name {
        "http" | "web_fetch" => params
            .get("url")
            .and_then(|v| v.as_str())
            .map(|u| truncate(u, 80)),
        "web_search" | "llm_context" => params
            .get("query")
            .and_then(|v| v.as_str())
            .map(|q| truncate(q, 60)),
        "memory_search" => params
            .get("query")
            .and_then(|v| v.as_str())
            .map(|q| truncate(q, 60)),
        "memory_write" => params
            .get("target")
            .and_then(|v| v.as_str())
            .map(|t| t.to_string()),
        "memory_read" => params
            .get("path")
            .and_then(|v| v.as_str())
            .map(|p| p.to_string()),
        "shell" => params
            .get("command")
            .and_then(|v| v.as_str())
            .map(|c| truncate(c, 60)),
        "message" => params
            .get("content")
            .and_then(|v| v.as_str())
            .map(|c| truncate(c, 40)),
        _ => {
            // Generic: show first string value
            if let Some(obj) = params.as_object() {
                obj.values()
                    .find_map(|v| v.as_str())
                    .map(|s| truncate(s, 50))
            } else {
                None
            }
        }
    };
    summary.filter(|s| !s.is_empty())
}

fn truncate(s: &str, max: usize) -> String {
    if s.len() <= max {
        s.to_string()
    } else {
        // Find a safe UTF-8 boundary
        let mut end = max.min(s.len());
        while end > 0 && !s.is_char_boundary(end) {
            end -= 1;
        }
        format!("{}...", &s[..end]) // safety: end is validated by is_char_boundary loop above
    }
}
use crate::types::step::{StepId, TokenUsage};
use crate::types::thread::{ThreadId, ThreadState};

/// Strongly-typed event identifier.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct EventId(pub Uuid);

impl EventId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }
}

impl Default for EventId {
    fn default() -> Self {
        Self::new()
    }
}

/// A recorded event in a thread's execution history.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ThreadEvent {
    pub id: EventId,
    pub thread_id: ThreadId,
    pub timestamp: DateTime<Utc>,
    pub kind: EventKind,
}

impl ThreadEvent {
    pub fn new(thread_id: ThreadId, kind: EventKind) -> Self {
        Self {
            id: EventId::new(),
            thread_id,
            timestamp: Utc::now(),
            kind,
        }
    }
}

/// The specific kind of event that occurred.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum EventKind {
    // ── Thread lifecycle ────────────────────────────────────
    StateChanged {
        from: ThreadState,
        to: ThreadState,
        reason: Option<String>,
    },

    // ── Step lifecycle ──────────────────────────────────────
    StepStarted {
        step_id: StepId,
    },
    StepCompleted {
        step_id: StepId,
        tokens: TokenUsage,
    },
    StepFailed {
        step_id: StepId,
        error: String,
    },

    // ── Action execution ────────────────────────────────────
    ActionExecuted {
        step_id: StepId,
        action_name: String,
        call_id: String,
        duration_ms: u64,
        /// Short human-readable summary of parameters (e.g., URL for http tool).
        #[serde(default, skip_serializing_if = "Option::is_none")]
        params_summary: Option<String>,
    },
    ActionFailed {
        step_id: StepId,
        action_name: String,
        call_id: String,
        error: String,
        /// Short human-readable summary of parameters.
        #[serde(default, skip_serializing_if = "Option::is_none")]
        params_summary: Option<String>,
    },

    // ── Capability leases ───────────────────────────────────
    LeaseGranted {
        lease_id: LeaseId,
        capability_name: String,
    },
    LeaseRevoked {
        lease_id: LeaseId,
        reason: String,
    },
    LeaseExpired {
        lease_id: LeaseId,
    },

    // ── Messages ────────────────────────────────────────────
    MessageAdded {
        role: String,
        content_preview: String,
    },

    // ── Thread tree ─────────────────────────────────────────
    ChildSpawned {
        child_id: ThreadId,
        goal: String,
    },
    ChildCompleted {
        child_id: ThreadId,
    },

    // ── Approval flow ───────────────────────────────────────
    ApprovalRequested {
        action_name: String,
        call_id: String,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        parameters: Option<serde_json::Value>,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        description: Option<String>,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        allow_always: Option<bool>,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        gate_name: Option<String>,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        params_summary: Option<String>,
    },
    ApprovalReceived {
        call_id: String,
        approved: bool,
    },

    // ── Self-improvement ──────────────────────────────────────
    SelfImprovementStarted,
    SelfImprovementComplete {
        prompt_updated: bool,
        patterns_added: usize,
    },
    SelfImprovementFailed {
        error: String,
    },

    // ── Skill activation ───────────────────────────────────────
    SkillActivated {
        skill_names: Vec<String>,
    },

    // ── Code execution instrumentation ────────────────────────
    /// Emitted when a code (REPL) execution attempt fails. Enables aggregate
    /// analysis of code execution failure modes to determine whether the
    /// runtime (Monty), the LLM, or tool dispatch is the primary source of
    /// failures.
    CodeExecutionFailed {
        step_id: StepId,
        /// Classified failure category.
        category: crate::types::step::CodeExecutionFailure,
        /// The error message text (truncated to 500 chars).
        error: String,
        /// Hash of the Python code that was executed, for dedup/correlation.
        #[serde(default, skip_serializing_if = "Option::is_none")]
        code_hash: Option<String>,
        /// Duration of the code execution attempt in milliseconds.
        #[serde(default)]
        duration_ms: u64,
    },

    // ── Orchestrator versioning ───────────────────────────────
    OrchestratorRollback {
        from_version: u64,
        to_version: u64,
        reason: String,
    },

    /// Unknown event kind — catch-all for forward compatibility during
    /// rolling deploys. Older binaries deserializing events written by
    /// newer binaries will produce this variant instead of failing.
    #[serde(other)]
    Unknown,
}

//! Step — the unit of execution within a thread.
//!
//! Each step corresponds to one LLM call plus its subsequent action
//! executions. This replaces the implicit "iteration" counter in the
//! existing `run_agentic_loop`.

use std::time::Duration;

use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use uuid::Uuid;

use crate::types::thread::ThreadId;

/// Strongly-typed step identifier.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct StepId(pub Uuid);

impl StepId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }
}

impl Default for StepId {
    fn default() -> Self {
        Self::new()
    }
}

/// Status of a step within its lifecycle.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum StepStatus {
    Pending,
    LlmCalling,
    Executing,
    Completed,
    Failed,
}

/// Which execution tier handles the step's code/actions.
///
/// Monty is the sole CodeAct/RLM executor. WASM and Docker are used for
/// third-party tool isolation and thread sandboxing (Phase 8), not for
/// running LLM-generated Python.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum ExecutionTier {
    /// Structured tool calls (JSON action calls from LLM).
    Structured,
    /// Embedded Python via Monty (CodeAct/RLM pattern).
    Scripting,
}

/// A single execution step within a thread.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Step {
    pub id: StepId,
    pub thread_id: ThreadId,
    /// 1-indexed sequence within the thread.
    pub sequence: usize,
    pub status: StepStatus,
    pub tier: ExecutionTier,
    pub llm_response: Option<LlmResponse>,
    pub action_results: Vec<ActionResult>,
    pub tokens_used: TokenUsage,
    pub started_at: DateTime<Utc>,
    pub completed_at: Option<DateTime<Utc>>,
}

impl Step {
    pub fn new(thread_id: ThreadId, sequence: usize) -> Self {
        Self {
            id: StepId::new(),
            thread_id,
            sequence,
            status: StepStatus::Pending,
            tier: ExecutionTier::Structured,
            llm_response: None,
            action_results: Vec::new(),
            tokens_used: TokenUsage::default(),
            started_at: Utc::now(),
            completed_at: None,
        }
    }
}

// ── LLM response types ─────────────────────────────────────

/// Response from the LLM: text, action calls, or executable code.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum LlmResponse {
    /// Final text response.
    Text(String),
    /// One or more action calls (with optional reasoning text).
    ActionCalls {
        calls: Vec<ActionCall>,
        content: Option<String>,
    },
    /// Executable Python code (CodeAct). Tool calls happen as function
    /// calls within the code; the runtime suspends at each one and
    /// delegates to the EffectExecutor.
    Code {
        code: String,
        content: Option<String>,
    },
}

/// A request from the LLM to execute a capability action.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ActionCall {
    /// Unique call identifier (echoed in the result).
    pub id: String,
    /// Action name (e.g. "web_fetch", "create_issue").
    pub action_name: String,
    /// Action parameters as JSON.
    pub parameters: serde_json::Value,
}

/// Result of executing a capability action.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ActionResult {
    /// The call ID this result corresponds to.
    pub call_id: String,
    /// The action that was executed.
    pub action_name: String,
    /// Output value.
    pub output: serde_json::Value,
    /// Whether this result represents an error.
    pub is_error: bool,
    /// How long the action took.
    #[serde(with = "duration_millis")]
    pub duration: Duration,
}

/// Classification of code execution failures.
///
/// Used by the instrumentation layer to distinguish Monty VM limitations
/// from LLM logic errors, tool dispatch failures, and resource exhaustion.
/// This data enables informed decisions about runtime alternatives.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum CodeExecutionFailure {
    /// Python parse error — LLM generated invalid syntax.
    SyntaxError,
    /// Python runtime error (NameError, TypeError, ValueError, etc.) —
    /// LLM logic bug or use of unsupported feature.
    RuntimeError,
    /// Name lookup failed — function/variable not in scope and not a known tool.
    NameLookup,
    /// Monty VM panicked (catch_unwind caught it). Indicates a Monty bug,
    /// not a user code issue.
    VmPanic,
    /// Resource limit hit (timeout, memory, or allocation cap).
    ResourceLimit,
    /// A tool call inside code returned an error.
    ToolError,
    /// OS operation attempted (blocked by sandbox).
    OsDenied,
}

impl std::fmt::Display for CodeExecutionFailure {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::SyntaxError => write!(f, "syntax_error"),
            Self::RuntimeError => write!(f, "runtime_error"),
            Self::NameLookup => write!(f, "name_lookup"),
            Self::VmPanic => write!(f, "vm_panic"),
            Self::ResourceLimit => write!(f, "resource_limit"),
            Self::ToolError => write!(f, "tool_error"),
            Self::OsDenied => write!(f, "os_denied"),
        }
    }
}

/// Token usage for a single LLM call.
#[derive(Debug, Clone, Copy, Default, Serialize, Deserialize)]
pub struct TokenUsage {
    pub input_tokens: u64,
    pub output_tokens: u64,
    pub cache_read_tokens: u64,
    pub cache_write_tokens: u64,
    /// USD cost for this call (populated by LlmBackend if cost data is available).
    pub cost_usd: f64,
}

impl TokenUsage {
    pub fn total(&self) -> u64 {
        self.input_tokens + self.output_tokens
    }
}

/// Serde helper for Duration as milliseconds.
mod duration_millis {
    use std::time::Duration;

    use serde::{Deserialize, Deserializer, Serializer};

    pub fn serialize<S: Serializer>(d: &Duration, s: S) -> Result<S::Ok, S::Error> {
        s.serialize_u64(d.as_millis() as u64)
    }

    pub fn deserialize<'de, D: Deserializer<'de>>(d: D) -> Result<Duration, D::Error> {
        let millis = u64::deserialize(d)?;
        Ok(Duration::from_millis(millis))
    }
}

