        assert_eq!(json.len(), 2);
        assert_eq!(json[0]["name"], "notion_notion_search");
        assert_eq!(json[0]["call_id"], "call_1");
        assert_eq!(json[1]["name"], "google_drive_tool");
        assert_eq!(json[1]["call_id"], "call_2");
    }

