    async fn run_code(
        code: &str,
        effects: Arc<dyn EffectExecutor>,
        thread: &Thread,
    ) -> Result<CodeExecutionResult, EngineError> {
        let leases = LeaseManager::new();
        let policy = PolicyEngine::new();
