        let code = r#"
data = []
while True:
    data.append("x" * 10000)
"#;
        let result = run_code(code, effects, &thread).await;
        // Either returns an error or the stdout contains an error message —
        // the key assertion is that it DOES NOT run forever.
        if let Ok(r) = result {
